mapper.select:
SELECT tpwc.prcs_cnfm_id, tpwc.rev_no, tpwc.rev_nm, tpwc.process_id, tpi.process_nm, tpwc.cnfm_at, tpwc.cnfm_yn, tpwc.use_yn as rev_use_yn, tpwc.cnfm_by, tpw.* FROM esg.tb_process_work_cnfm tpwc LEFT JOIN esg.tb_process_work tpw on tpwc.prcs_cnfm_id = tpw.prcs_cnfm_id LEFT JOIN esg.tb_process_info tpi on tpi.process_id = tpwc.process_id WHERE 1=1
AND tpwc.process_id = #{processId} AND tpwc.rev_no = #{revNo}
AND tpwc.cnfm_yn = 'Y' AND tpw.use_yn = 'Y' AND tpi.comp_id = #{compId}
ORDER BY tpw.use_yn DESC, tpwc.process_id, tpw.ord_seq, tpw.created_at

SELECT *
FROM esg.tb_process_work_cnfm
WHERE 1=1
  AND process_id = #{processId}
ORDER BY CAST(rev_no AS BIGINT) DESC
    LIMIT 1;

